import DOM_SELECTORS from "../selectors/cardSelectorsMap";
import TOKENIZATION_MAPPER from "../utils/tokenizationMapper";
import { ONE_CLICK_TRANSACTION_TYPE, LOADER_BUTTON_ACTIVE_CLASS } from "../utils/constants";
import { getPayloadToUrl } from "../utils/urlHelpers";

import useForm from "../components/useForm";
import useToggleDisplay from "../utils/useToggleDisplay";
import useToggleLoader from "../utils/useToggleLoader";
import useNotice from "../components/useNotice";
import useModals from "../utils/useModals";
import paymentHelper from "../utils/usePaymentHelper";
import useOneClickPaymentHelper from "../utils/useOneClickPaymentHelper";

const cardController = () => {
    let CardService = null;
    let p24Notices = null;

    const {
        PRZELEWY24_ADD_CARD_BUTTON,
        PRZELEWY24_CARD_NOTICE_WRAPPER,
        PRZELEWY24_CARD_PAYMENT_INPUT,
        PRZELEWY24_CARD_REGULATIONS_WRAPPER,
        PRZELEWY24_CARD_SUBMIT_WRAPPER,
        PRZELEWY24_CARD_TOKENIZER_BACK_BUTTON,
        PRZELEWY24_CARD_TOKENIZER_SUBMIT_BUTTON,
        PRZELEWY24_CARD_TOKENIZER_WRAPPER,
        PRZELEWY24_CARD_WHITE_LABEL_LOADER,
        PRZELEWY24_CARD_WHITE_LABEL_WRAPPER,
        PRZELEWY24_CARD_WHITE_LABEL_ID,
        PRZELEWY24_SAVED_CARDS_SUBMIT,
        PRZELEWY24_SAVED_CARDS_WRAPPER
    } = DOM_SELECTORS;

    const { toggle } = useToggleDisplay();
    const { getSelectedCard, getSelectedPaymentOption, getUrlFormFromPaymentOption, getRegulations, } = paymentHelper();
    const { registerCardTransaction } = useForm();
    const { showNotice, hideNotice } = useNotice();
    const { toggleLoader } = useToggleLoader();
    const { showCardWhiteLabelModal, handleIframeClosure } = useModals();
    const { ensureAddressesAreSaved } = useOneClickPaymentHelper();

    const setCardWhiteLabelListeners = (urlReturn) => {
        CardService.onNeedInteraction = () => {
            toggleLoader(PRZELEWY24_CARD_WHITE_LABEL_LOADER, false);
        }
        CardService.onNoNeedInteraction = () => {
            toggleLoader(PRZELEWY24_CARD_WHITE_LABEL_LOADER, false);

            setTimeout(() => {
                handleIframeClosure(
                    PRZELEWY24_CARD_WHITE_LABEL_WRAPPER,
                    PRZELEWY24_CARD_WHITE_LABEL_LOADER,
                    urlReturn
                );
            }, 60000);
        }
        CardService.onSuccess = () => {
            handleIframeClosure(
                PRZELEWY24_CARD_WHITE_LABEL_WRAPPER,
                PRZELEWY24_CARD_WHITE_LABEL_LOADER,
                urlReturn
            );
        }
        CardService.onFailed = () => {
            console.error('Failed transaction from white label handler');
            handleIframeClosure(
                PRZELEWY24_CARD_WHITE_LABEL_WRAPPER,
                PRZELEWY24_CARD_WHITE_LABEL_LOADER,
                urlReturn
            );
        }
    }

    const loadCardWhiteLabel = async (token) => {
        await CardService.loadWhiteLabel(
            PRZELEWY24_CARD_WHITE_LABEL_ID,
            token,
            () => showCardWhiteLabelModal(PRZELEWY24_CARD_WHITE_LABEL_WRAPPER),
        );
    }

    const handleRegulationsChange = (event) => {
        const regulationsWrapper = event.target.closest(PRZELEWY24_CARD_REGULATIONS_WRAPPER);
        const submitWrapper = regulationsWrapper?.closest(PRZELEWY24_CARD_SUBMIT_WRAPPER);
        const submitButtons = submitWrapper?.querySelectorAll(`button[type="submit"]`);

        if (!submitButtons) return;

        const regulations = getRegulations(regulationsWrapper);
        const isRegulationsChecked = Object.values(regulations).every((value) => value);

        submitButtons?.forEach((button) => {
            button.disabled = !isRegulationsChecked;
        });
    }

    const handleRegisterCardTransaction = async (payload, url) => {
        let token, urlReturn, urlForm;
        const payloadUrl = getPayloadToUrl(payload);

        urlForm = url || getUrlFormFromPaymentOption(getSelectedPaymentOption());

        try {
            const response = await registerCardTransaction(urlForm, payloadUrl);

            if (response?.errors) {
                showNotice(PRZELEWY24_CARD_NOTICE_WRAPPER, response?.errors, 'danger');
            } else {
                token = response?.token;
                urlReturn = response?.urlReturn;
            }
        } catch (errorResponse) {
            if (errorResponse.error) {
                console.error(errorResponse.error);
            } else {
                console.error(errorResponse);
            }
            showNotice(
                PRZELEWY24_CARD_NOTICE_WRAPPER,
                p24Notices?.transactionError || 'Error while processing transaction.',
                'danger'
            );
        }

        return { token, urlReturn }
    }

    const handleCardWhiteLabelTransaction = async (payload, url = '') => {
        const { token, urlReturn } = await handleRegisterCardTransaction(payload, url);

        if (!token || !urlReturn) {
            console.error('Token or urlReturn is missing.');
            return;
        }

        setCardWhiteLabelListeners(urlReturn);
        await loadCardWhiteLabel(token);
    }

    const handleTokenizerSubmit = async (event) => {
        event.preventDefault();
        hideNotice(PRZELEWY24_CARD_NOTICE_WRAPPER);

        // CRITICAL: Ensure addresses are saved before processing card tokenizer payment (module-aware)
        console.log('[Card Tokenizer] Checking if address saving is required for current checkout module...');
        const addressesSaved = await ensureAddressesAreSaved();

        if (!addressesSaved) {
            console.error('[Card Tokenizer] Cannot proceed - addresses are not saved or validation failed');
            showNotice(
                PRZELEWY24_CARD_NOTICE_WRAPPER,
                p24Notices?.addressError || 'Please complete your address information before proceeding with payment.',
                'danger'
            );
            return;
        }

        console.log('[Card Tokenizer] Address requirements satisfied, proceeding with card tokenizer payment...');

        const submitButton = event.target;
        const saveOneClick = submitButton.dataset.saveOneClick;

        submitButton.disabled = true;
        submitButton.classList.add(LOADER_BUTTON_ACTIVE_CLASS);

        CardService.setSaveOneClick(!!saveOneClick);
        await CardService.prepareData();
        const error = CardService.getError();

        if (error) {
            console.error('Error while preparing data from tokenizer.');
            showNotice(
                PRZELEWY24_CARD_NOTICE_WRAPPER,
                `${p24Notices?.tokenizerError || 'Error while preparing data from tokenizer.'} ${error}`,
                'danger'
            );
            submitButton.disabled = false;
            submitButton.classList.remove(LOADER_BUTTON_ACTIVE_CLASS);
            return;
        }

        const data = CardService.getPaymentData();
        const { cardType, refId, hash, tokenization } = data;
        const cardSubmitWrapper = submitButton.closest(PRZELEWY24_CARD_SUBMIT_WRAPPER);
        const url = cardSubmitWrapper?.dataset.url;
        const regulations = getRegulations(cardSubmitWrapper?.querySelector(PRZELEWY24_CARD_REGULATIONS_WRAPPER));

        const payload = {
            ref_id: refId,
            card_type: cardType,
            hash: hash,
            transaction_type: TOKENIZATION_MAPPER[tokenization] ?? tokenization,
            ...regulations
        }

        await handleCardWhiteLabelTransaction(payload, url);

        submitButton.disabled = false;
        submitButton.classList.remove(LOADER_BUTTON_ACTIVE_CLASS);
    }

    const handleOneClickSubmit = async (event) => {
        event.preventDefault();
        hideNotice(PRZELEWY24_CARD_NOTICE_WRAPPER);

        // CRITICAL: Ensure addresses are saved before processing one-click card payment (module-aware)
        console.log('[Card One-Click] Checking if address saving is required for current checkout module...');
        const addressesSaved = await ensureAddressesAreSaved();

        if (!addressesSaved) {
            console.error('[Card One-Click] Cannot proceed - addresses are not saved or validation failed');
            showNotice(
                PRZELEWY24_CARD_NOTICE_WRAPPER,
                p24Notices?.addressError || 'Please complete your address information before proceeding with payment.',
                'danger'
            );
            return;
        }

        console.log('[Card One-Click] Address requirements satisfied, proceeding with one-click card payment...');

        const submitButton = event.target;
        const selectedCard = getSelectedCard();
        const refId = selectedCard?.value;

        if (!refId || !selectedCard) {
            console.error('Error while getting refId from selected card or selected card is missing.');
            showNotice(
                PRZELEWY24_CARD_NOTICE_WRAPPER,
                p24Notices?.selectCard || 'Please select a card.',
                'danger'
            );
            return;
        }

        CardService.resetWhiteLabelIframe();
        const { cardType, cardId } = selectedCard.dataset;
        const cardSubmitWrapper = submitButton.closest(PRZELEWY24_CARD_SUBMIT_WRAPPER);
        const url = cardSubmitWrapper?.dataset.url;
        const regulations = getRegulations(cardSubmitWrapper?.querySelector(PRZELEWY24_CARD_REGULATIONS_WRAPPER));

        const payload = {
            ref_id: refId,
            card_type: cardType,
            card_id: cardId,
            transaction_type: ONE_CLICK_TRANSACTION_TYPE,
            ...regulations
        }

        submitButton.disabled = true;
        submitButton.classList.add(LOADER_BUTTON_ACTIVE_CLASS);

        await handleCardWhiteLabelTransaction(payload, url);

        submitButton.disabled = false;
        submitButton.classList.remove(LOADER_BUTTON_ACTIVE_CLASS);
    }

    const handleCardFormToggle = (event) => {
        event.preventDefault();
        const cardTokenizer = document.querySelector(PRZELEWY24_CARD_TOKENIZER_WRAPPER);
        const savedCards = document.querySelector(PRZELEWY24_SAVED_CARDS_WRAPPER);

        if (cardTokenizer && savedCards) {
            toggle(cardTokenizer, !cardTokenizer.checkVisibility());
            toggle(savedCards, !savedCards.checkVisibility());
        }
    }

    const initCardTokenizer = async () => {
        await CardService.loadTokenizer();
        CardService.initTokenizerHandler();
    }

    const attachEvents = () => {
        document.querySelector(PRZELEWY24_ADD_CARD_BUTTON)?.removeEventListener('click', handleCardFormToggle);
        document.querySelector(PRZELEWY24_ADD_CARD_BUTTON)?.addEventListener('click', handleCardFormToggle);

        document.querySelector(PRZELEWY24_CARD_TOKENIZER_BACK_BUTTON)?.removeEventListener('click', handleCardFormToggle);
        document.querySelector(PRZELEWY24_CARD_TOKENIZER_BACK_BUTTON)?.addEventListener('click', handleCardFormToggle);

        document.querySelector(PRZELEWY24_SAVED_CARDS_SUBMIT)?.removeEventListener('click', handleOneClickSubmit);
        document.querySelector(PRZELEWY24_SAVED_CARDS_SUBMIT)?.addEventListener('click', handleOneClickSubmit);

        document.querySelectorAll(PRZELEWY24_CARD_TOKENIZER_SUBMIT_BUTTON)?.forEach((button) => {
            button.removeEventListener('click', handleTokenizerSubmit);
            button.addEventListener('click', handleTokenizerSubmit);
        });

        document.querySelectorAll(PRZELEWY24_CARD_REGULATIONS_WRAPPER)?.forEach((regulationsWrapper) => {
            regulationsWrapper.querySelectorAll('input[type="checkbox"]')?.forEach((input) => {
                input.removeEventListener('change', handleRegulationsChange);
                input.addEventListener('change', handleRegulationsChange);
            });
        });
    }

    const init = async (P24CardService = null) => {
        const cardPaymentAvailable = document.querySelector(PRZELEWY24_CARD_PAYMENT_INPUT);
        p24Notices = window.p24Notices || null;

        if (P24CardService && cardPaymentAvailable) {
            CardService = P24CardService;
            await initCardTokenizer();
            attachEvents();
        } else if (cardPaymentAvailable && !P24CardService) {
            console.error('Error while initializing CardService. Config or card payment is missing.');
            showNotice(
                PRZELEWY24_CARD_NOTICE_WRAPPER,
                p24Notices?.serviceError || 'Error while loading card service.',
                'danger'
            );
        }
    }

    return { init };
}

export default cardController;
