/**
 * Utility for saving addresses in ETS One Page Checkout before processing one-click payments
 * This solves the issue where addresses are only saved when submitCompleteMyOrder is clicked,
 * but one-click payment methods need addresses saved before their own checkout process.
 *
 * SPECIFIC TO ETS ONE PAGE CHECKOUT MODULE
 */

const useEtsAddressSaver = () => {
    /**
     * Pre-validate form before attempting to save addresses
     * Checks for login requirements and basic field validation
     * @returns {Object} - {isValid: boolean, errorMessage: string}
     */
    const preValidateForm = () => {
        const typeCheckoutOptions = document.querySelector('input[name="type-checkout-options"]:checked');
        if (typeCheckoutOptions && typeCheckoutOptions.dataset.type === 'login') {
            return {
                isValid: false,
                errorMessage: window.p24Notices?.loginBeforeText || 'Please log in before proceeding with payment.'
            };
        }

        const requiredElements = document.querySelectorAll('.block-address input.is_required, .block-address select.is_required, .block-address textarea.is_required');

        const hasEmptyRequiredFields = Array.from(requiredElements).some(element => {
            if (!element.offsetParent && element.offsetHeight === 0 && element.offsetWidth === 0) {
                return false;
            }

            const isEmpty = !element.value || element.value.trim() === '';
            const isSelectWithNoSelection = element.tagName === 'SELECT' && (element.value === '' || element.value === '0');
            return isEmpty || isSelectWithNoSelection;
        });

        if (hasEmptyRequiredFields) {
            return {
                isValid: false,
                errorMessage: window.p24Notices?.addressError || 'Please complete your address information before proceeding with payment.'
            };
        }

        return { isValid: true, errorMessage: null };
    };

    /**
     * Programmatically trigger the ETS one-page checkout address saving process
     * This mimics the submitCompleteMyOrder button click but stops before payment processing
     *
     * @returns {Promise<boolean>} - Returns true if addresses were saved successfully, false otherwise
     */
    const saveAddressesBeforePayment = () => {
        return new Promise((resolve, reject) => {
            const form = document.getElementById('form_ets_onepagecheckout');
            const submitButton = document.querySelector('button[name="submitCompleteMyOrder"]');

            if (!form || !submitButton) {
                console.warn('[P24 ETS Address Saver] ETS one-page checkout form or submit button not found');
                resolve(false);
                return;
            }

            if (document.querySelector('.loading')) {
                console.warn('[P24 ETS Address Saver] Another operation is already in progress');
                resolve(false);
                return;
            }

            const validation = preValidateForm();
            if (!validation.isValid) {
                console.warn('[P24 ETS Address Saver] Form validation failed:', validation.errorMessage);

                const errorContainer = document.getElementById('onepagecheckout-information-errros');
                if (errorContainer) {
                    errorContainer.innerHTML = '<div class="bootstrap"><div class="module_error alert alert-danger"><button class="close" type="button" data-dismiss="alert">x</button>' + validation.errorMessage + '</div></div>';
                    window.scrollTo({ top: 0, behavior: 'smooth' });
                }

                resolve(false);
                return;
            }

            const formData = new FormData(form);
            formData.append('submitCompleteMyOrder', 1);
            submitButton.classList.add('loading');

            document.querySelectorAll('.ets_opc_error').forEach(error => error.remove());
            const errorContainer = document.getElementById('onepagecheckout-information-errros');
            if (errorContainer) {
                errorContainer.innerHTML = '';
            }

            fetch(form.getAttribute('action'), {
                method: 'POST',
                body: formData
            })
            .then(response => response.json())
            .then(json => {
                submitButton.classList.remove('loading');

                if (json.hasError) {
                    console.error('[P24 ETS Address Saver] Address validation errors:', json.errors);

                    if (json.field_errors) {
                        json.field_errors.forEach(fieldError => {
                            const field = document.getElementById(fieldError.field);
                            if (field) {
                                const errorElement = document.createElement('span');
                                errorElement.className = 'ets_opc_error';
                                errorElement.textContent = fieldError.error;

                                if (field.closest('.form-group')) {
                                    field.closest('.form-group').appendChild(errorElement);
                                } else if (field.closest('.input-group')) {
                                    field.closest('.input-group').after(errorElement);
                                } else {
                                    field.parentNode.appendChild(errorElement);
                                }
                            }
                        });
                    }

                    if (errorContainer && json.errors) {
                        errorContainer.innerHTML = json.errors;
                    }

                    window.scrollTo({ top: 0, behavior: 'smooth' });

                    resolve(false);
                } else {
                    console.log('[P24 ETS Address Saver] Addresses saved successfully');

                    if (json.jsCustomer && window.prestashop) {
                        window.prestashop.customer = json.jsCustomer;
                    }

                    if (json.customer_block) {
                        const customerBlock = document.querySelector('.block-customer .block-content');
                        if (customerBlock) {
                            customerBlock.innerHTML = json.customer_block;
                        }

                        const deliveryAddresses = document.getElementById('delivery-addresses');
                        if (deliveryAddresses && json.shipping_address) {
                            deliveryAddresses.innerHTML = json.shipping_address;
                        }

                        const invoiceAddresses = document.getElementById('invoice-addresses');
                        if (invoiceAddresses && json.invoice_address) {
                            invoiceAddresses.innerHTML = json.invoice_address;
                        }
                    }

                    resolve(true);
                }
            })
            .catch(error => {
                console.error('[P24 ETS Address Saver] Error saving addresses:', error);
                submitButton.classList.remove('loading');
                resolve(false);
            });
        });
    };

    /**
     * Check if addresses are already saved and valid
     * @returns {boolean} - True if addresses appear to be saved
     */
    const areAddressesSaved = () => {
        const validation = preValidateForm();
        if (!validation.isValid) {
            console.log('[P24 ETS Address Saver] Form validation failed - required fields empty, saving required to show errors');
            return false;
        }

        const shippingAddressSelect = document.querySelector('select#use_shipping_address');
        const invoiceAddressSelect = document.querySelector('select#use_invoice_address');

        const hasShippingDropdown = shippingAddressSelect && shippingAddressSelect.options.length > 1;
        const hasInvoiceDropdown = invoiceAddressSelect && invoiceAddressSelect.options.length > 1;

        if (hasShippingDropdown || hasInvoiceDropdown) {
            const shippingValue = shippingAddressSelect ? shippingAddressSelect.value : 'none';
            const invoiceValue = invoiceAddressSelect ? invoiceAddressSelect.value : 'none';

            console.log('[P24 ETS Address Saver] Address dropdowns detected - shipping: ' + shippingValue + ', invoice: ' + invoiceValue + '. Address saving required to process selection.');
            return false;
        }

        if (window.prestashop && window.prestashop.customer) {
            const customer = window.prestashop.customer;
            const hasAddresses = Array.isArray(customer.addresses)
                ? customer.addresses.length > 0
                : Object.keys(customer.addresses || {}).length > 0;

            if (hasAddresses) {
                console.log('[P24 ETS Address Saver] Customer has existing addresses, no dropdowns, and form validation passed');
                return true;
            }
        }

        console.log('[P24 ETS Address Saver] Form validation passed but no addresses found, saving required');
        return false;
    };

    /**
     * Ensure addresses are saved before proceeding with one-click payment
     * @returns {Promise<boolean>} - True if addresses are ready for payment
     */
    const ensureAddressesAreSaved = async () => {
        if (areAddressesSaved()) {
            console.log('[P24 ETS Address Saver] Addresses already saved, proceeding with payment');
            return true;
        }

        console.log('[P24 ETS Address Saver] Addresses not saved, attempting to save...');

        const saved = await saveAddressesBeforePayment();

        if (!saved) {
            console.error('[P24 ETS Address Saver] Failed to save addresses before payment');
            return false;
        }

        return true;
    };

    return {
        saveAddressesBeforePayment,
        areAddressesSaved,
        ensureAddressesAreSaved
    };
};

export default useEtsAddressSaver;
