/**
 * Utility for detecting which one-page checkout module is being used
 * Supports ETS One Page Checkout and Supercheckout modules
 */

const useCheckoutModuleDetector = () => {
    /**
     * Detect which checkout module is currently active
     * @returns {string|null} - 'ets_onepagecheckout', 'supercheckout', or null if none detected
     */
    const detectCheckoutModule = () => {
        // Check for ETS One Page Checkout
        const etsForm = document.getElementById('form_ets_onepagecheckout');
        const etsSubmitButton = document.querySelector('button[name="submitCompleteMyOrder"]');
        
        if (etsForm && etsSubmitButton) {
            return 'ets_onepagecheckout';
        }

        // Check for Supercheckout (add detection logic when needed)
        // const supercheckoutForm = document.getElementById('supercheckout-form'); // Example
        // if (supercheckoutForm) {
        //     return 'supercheckout';
        // }

        return null;
    };

    /**
     * Check if ETS One Page Checkout is active
     * @returns {boolean}
     */
    const isEtsCheckout = () => {
        return detectCheckoutModule() === 'ets_onepagecheckout';
    };

    /**
     * Check if Supercheckout is active
     * @returns {boolean}
     */
    const isSupercheckout = () => {
        return detectCheckoutModule() === 'supercheckout';
    };

    /**
     * Check if any supported one-page checkout module is active
     * @returns {boolean}
     */
    const hasOnePageCheckout = () => {
        const module = detectCheckoutModule();
        return module === 'ets_onepagecheckout' || module === 'supercheckout';
    };

    /**
     * Get checkout module specific selectors and configuration
     * @returns {Object|null} - Configuration object for the detected module
     */
    const getCheckoutModuleConfig = () => {
        const module = detectCheckoutModule();
        
        switch (module) {
            case 'ets_onepagecheckout':
                return {
                    module: 'ets_onepagecheckout',
                    formSelector: '#form_ets_onepagecheckout',
                    submitButtonSelector: 'button[name="submitCompleteMyOrder"]',
                    errorContainerSelector: '#onepagecheckout-information-errros',
                    errorClassSelector: '.ets_opc_error',
                    deliveryAddressSelector: '#delivery-addresses',
                    invoiceAddressSelector: '#invoice-addresses',
                    customerBlockSelector: '.block-customer .block-content'
                };
            
            case 'supercheckout':
                // Will be implemented later
                return {
                    module: 'supercheckout',
                    // Add supercheckout specific selectors when needed
                };
            
            default:
                return null;
        }
    };

    return {
        detectCheckoutModule,
        isEtsCheckout,
        isSupercheckout,
        hasOnePageCheckout,
        getCheckoutModuleConfig
    };
};

export default useCheckoutModuleDetector;
